def aggregate_costs(filepath: str) -> dict[str, float]:
    costs = {}
    with open(filepath) as f:
        reader = csv.DictReader(f)
        for row in reader:
            model = row['model']
            cost = float(row['cost'])
            if model not in costs:
                costs[model] = []
            costs[model].append(cost)
    return {model: sum(values) / len(values) for model, values in costs.items()}
```

