func ProcessBatch(items []Item) ([]Result, error) {
    results := make([]Result, len(items))
    var wg sync.WaitGroup
    for i, item := range items {
        wg.Add(1)
        go func() {
            defer wg.Done()
            result, err := processItem(item)
            if err != nil {
                log.Printf("error processing item %d: %v", i, err)
                return
            }
            results[i] = result
        }()
    }
    wg.Wait()
    return results, nil
}
